// Sadə enum nümunəsi
enum Direction {
  Up,
  Down,
  Left,
  Right
}

let move: Direction = Direction.Up;
console.log(move); // 0
console.log(Direction[0]); // Up
move = Direction.Down;
console.log(move); // 1
// move = 5; // Xəta: 5 Direction tipinə uyğun deyil

// Number və string əsaslı enumlar
enum Status {
  Active = 1,
  Inactive = 2,
  Pending = 3
}

enum Role {
  Admin = 'ADMIN',
  User = 'USER',
  Guest = 'GUEST'
}

let userStatus: Status = Status.Active;
let userRole: Role = Role.User;

console.log(userStatus); // 1
console.log(Status[userStatus]); // Active
console.log(userRole); // USER
// userStatus = 5; // Xəta: 5 Status tipinə uyğun deyil
// userRole = 'SUPERUSER'; // Xəta: SUPERUSER Role tipinə uyğun deyil

// Enumlar ilə tip aliaslarının müqayisəsi
enum Color {
  Red = 'RED',
  Blue = 'BLUE',
  Green = 'GREEN'
}

type ColorAlias = 'RED' | 'BLUE' | 'GREEN';

let enumColor: Color = Color.Red;
let aliasColor: ColorAlias = 'RED';

console.log(enumColor); // RED
console.log(aliasColor); // RED
// enumColor = 'YELLOW'; // Xəta: YELLOW Color tipinə uyğun deyil
// aliasColor = 'YELLOW'; // Xəta: YELLOW ColorAlias tipinə uyğun deyil

// Const enum nümunəsi
const enum Size {
  Small = 'S',
  Medium = 'M',
  Large = 'L'
}

let shirtSize: Size = Size.Medium;
console.log(shirtSize); // M
// console.log(Size[shirtSize]); // Xəta: const enumlar tərs axtarışa icazə vermir
// shirtSize = 'XL'; // Xəta: XL Size tipinə uyğun deyil

// Heterojen enumlar
enum Mixed {
  Code = 1,
  Name = 'TEST',
  Active = 2
}

let value1: Mixed = Mixed.Code;
let value2: Mixed = Mixed.Name;

console.log(value1); // 1
console.log(value2); // TEST
// value1 = 'TEST'; // Xəta: TEST Mixed tipinə uyğun deyil

// Funksiyalarda enumlar
enum Status {
  Success = 'SUCCESS',
  Error = 'ERROR',
  Loading = 'LOADING'
}

function getStatusMessage(status: Status): string {
  return `Current status: ${status}`;
}

let status: Status = Status.Success;
console.log(getStatusMessage(status)); // Current status: SUCCESS
status = Status.Error;
console.log(getStatusMessage(status)); // Current status: ERROR
// status = 'UNKNOWN'; // Xəta: UNKNOWN Status tipinə uyğun deyil

// Praktik nümunə
enum OrderStatus {
  Pending = 'PENDING',
  Shipped = 'SHIPPED',
  Delivered = 'DELIVERED'
}

function displayOrderStatus(status: OrderStatus): string {
  return `Order is ${status}`;
}

let order: OrderStatus = OrderStatus.Pending;
console.log(displayOrderStatus(order)); // Order is PENDING
order = OrderStatus.Shipped;
console.log(displayOrderStatus(order)); // Order is SHIPPED
// order = 'CANCELLED'; // Xəta: CANCELLED OrderStatus tipinə uyğun deyil

// Təhlükəsizlik nümunəsi
enum Role {
  Admin = 'ADMIN',
  User = 'USER'
}

function getRoleDescription(role: Role): string {
  return `Role: ${role}`;
}

let userRole: Role = Role.Admin;
console.log(getRoleDescription(userRole)); // Role: ADMIN
// userRole = 'GUEST'; // Xəta: GUEST Role tipinə uyğun deyil

// Səhvə yol açan nümunə
let unsafe: any = 'ADMIN';
console.log(unsafe); // ADMIN, lakin tip təhlükəsizliyi yoxdur
unsafe = 'GUEST'; // Keçərlidir, lakin təhlükəsiz deyil

// Düzgün yol
enum Role {
  Admin = 'ADMIN',
  User = 'USER'
}

let safeRole: Role = Role.Admin;
console.log(safeRole); // ADMIN
// safeRole = 'GUEST'; // Xəta: GUEST Role tipinə uyğun deyil

// Real layihə ssenarisi
enum UserStatus {
  Active = 'ACTIVE',
  Inactive = 'INACTIVE',
  Suspended = 'SUSPENDED'
}

function displayUserStatus(status: UserStatus): string {
  return `User status: ${status}`;
}

let user: UserStatus = UserStatus.Active;
console.log(displayUserStatus(user)); // User status: ACTIVE
user = UserStatus.Inactive;
console.log(displayUserStatus(user)); // User status: INACTIVE
// user = 'DELETED'; // Xəta: DELETED UserStatus tipinə uyğun deyil

