// Simple enum example
enum Direction {
  Up,
  Down,
  Left,
  Right
}

let move: Direction = Direction.Up;
console.log(move); // 0
console.log(Direction[0]); // Up
move = Direction.Down;
console.log(move); // 1
// move = 5; // Error: 5 is not assignable to Direction

// Number and string-based enums
enum Status {
  Active = 1,
  Inactive = 2,
  Pending = 3
}

enum Role {
  Admin = 'ADMIN',
  User = 'USER',
  Guest = 'GUEST'
}

let userStatus: Status = Status.Active;
let userRole: Role = Role.User;

console.log(userStatus); // 1
console.log(Status[userStatus]); // Active
console.log(userRole); // USER
// userStatus = 5; // Error: 5 is not assignable to Status
// userRole = 'SUPERUSER'; // Error: SUPERUSER is not assignable to Role

// Enums vs. type aliases
enum Color {
  Red = 'RED',
  Blue = 'BLUE',
  Green = 'GREEN'
}

type ColorAlias = 'RED' | 'BLUE' | 'GREEN';

let enumColor: Color = Color.Red;
let aliasColor: ColorAlias = 'RED';

console.log(enumColor); // RED
console.log(aliasColor); // RED
// enumColor = 'YELLOW'; // Error: YELLOW is not assignable to Color
// aliasColor = 'YELLOW'; // Error: YELLOW is not assignable to ColorAlias

// Const enum example
const enum Size {
  Small = 'S',
  Medium = 'M',
  Large = 'L'
}

let shirtSize: Size = Size.Medium;
console.log(shirtSize); // M
// console.log(Size[shirtSize]); // Error: const enums do not support reverse mapping
// shirtSize = 'XL'; // Error: XL is not assignable to Size

// Heterogeneous enums
enum Mixed {
  Code = 1,
  Name = 'TEST',
  Active = 2
}

let value1: Mixed = Mixed.Code;
let value2: Mixed = Mixed.Name;

console.log(value1); // 1
console.log(value2); // TEST
// value1 = 'TEST'; // Error: TEST is not assignable to Mixed

// Enums in functions
enum Status {
  Success = 'SUCCESS',
  Error = 'ERROR',
  Loading = 'LOADING'
}

function getStatusMessage(status: Status): string {
  return `Current status: ${status}`;
}

let status: Status = Status.Success;
console.log(getStatusMessage(status)); // Current status: SUCCESS
status = Status.Error;
console.log(getStatusMessage(status)); // Current status: ERROR
// status = 'UNKNOWN'; // Error: UNKNOWN is not assignable to Status

// Practical example
enum OrderStatus {
  Pending = 'PENDING',
  Shipped = 'SHIPPED',
  Delivered = 'DELIVERED'
}

function displayOrderStatus(status: OrderStatus): string {
  return `Order is ${status}`;
}

let order: OrderStatus = OrderStatus.Pending;
console.log(displayOrderStatus(order)); // Order is PENDING
order = OrderStatus.Shipped;
console.log(displayOrderStatus(order)); // Order is SHIPPED
// order = 'CANCELLED'; // Error: CANCELLED is not assignable to OrderStatus

// Security example
enum Role {
  Admin = 'ADMIN',
  User = 'USER'
}

function getRoleDescription(role: Role): string {
  return `Role: ${role}`;
}

let userRole: Role = Role.Admin;
console.log(getRoleDescription(userRole)); // Role: ADMIN
// userRole = 'GUEST'; // Error: GUEST is not assignable to Role

// Error-prone example
let unsafe: any = 'ADMIN';
console.log(unsafe); // ADMIN, but no type safety
unsafe = 'GUEST'; // Valid, but unsafe

// Correct approach
enum Role {
  Admin = 'ADMIN',
  User = 'USER'
}

let safeRole: Role = Role.Admin;
console.log(safeRole); // ADMIN
// safeRole = 'GUEST'; // Error: GUEST is not assignable to Role

// Real-world scenario
enum UserStatus {
  Active = 'ACTIVE',
  Inactive = 'INACTIVE',
  Suspended = 'SUSPENDED'
}

function displayUserStatus(status: UserStatus): string {
  return `User status: ${status}`;
}

let user: UserStatus = UserStatus.Active;
console.log(displayUserStatus(user)); // User status: ACTIVE
user = UserStatus.Inactive;
console.log(displayUserStatus(user)); // User status: INACTIVE
// user = 'DELETED'; // Error: DELETED is not assignable to UserStatus

